//
import { Registry } from '../../core/zc-registry';
import { each, isArray, arrayIncludes, isObject } from '../../utils/zcutils';
import { ALLOWED_CONFIG_OPERATORS } from '../operators/config/allowed-config-operators';

let customType = ['pattern', 'gradient', 'image'];
function convertOperatorToProperty(config) {
    if (!isObject(config)) {
        return config;
    }

    let obj = {},
        self = this;
    each(config, (value, prop) => {
        let _;
        if (value && value._type && value._type != "expression") {
            let a = arrayIncludes(customType, value._type) && convertOperatorToProperty({ ...value, _type: null });
            _ = ALLOWED_CONFIG_OPERATORS.get(value._type).call(self, value, a);
        } else if (isArray(value)) {
            _ = value.map(_ => convertOperatorToProperty(_));
        } else {
            _ = value;
        }
        obj[prop] = _;
    });

    return obj;
}

export { convertOperatorToProperty };
Registry.setComponent('markUtils.convertOperatorToProperty', convertOperatorToProperty);
